// Toma el primer elemento del array de entrada
const item = Array.isArray($input.item.json) ? $input.item.json[0] : $input.item.json;

// Accede a los datos de la llamada desde body.call
const call = item.body?.call || {};

// Accede al array de data si existe
const dataArray = item.data || [];

// Concatenar todos los resúmenes previos en uno solo
let resumenesPrevios = "";
if (dataArray.length > 0) {
  resumenesPrevios = dataArray
    .map((data, index) => {
      const fecha = data.fecha_llamada
        ? new Date(data.fecha_llamada).toLocaleDateString("es-MX")
        : "Fecha no disponible";
      return `[Llamada ${index + 1} - ${fecha}]: ${data.resumen || "Sin resumen"}`;
    })
    .join("\n\n");
}

// Construir instrucciones breves para el agente
const instruccionesBrevesAgente = `
Cliente: ${item.nombre || "Sin nombre"}
Empresa: ${item.empresa || "No especificada"}
Servicio de interés: ${item.servicio || "No especificado"}
País: ${item.pais || "No especificado"}
Estado Lead: ${item.estado_lead || "Desconocido"}
Score: ${item.score_lead || "N/A"}/100
Fuente: ${item.fuente || "Desconocida"}
${item.fecha_cita ? `Cita agendada: ${item.fecha_cita_legible || item.fecha_cita}` : "Sin cita agendada"}
${resumenesPrevios ? `\n📋 Historial de llamadas previas:\n${resumenesPrevios}` : ""}
${call.call_analysis?.call_summary ? `\n📞 Resumen de llamada actual: ${call.call_analysis.call_summary}` : ""}
`.trim();

// Construye metadata combinando todos los datos disponibles
const metadata = {
  webhookUrl: item.webhookUrl || "",
  id: item.id || "",
  lead_id: item.lead_id || "",
  fb_click_id: item.fb_click_id || "",
  nombre: item.nombre || "",
  email: item.email || "",
  telefono: item.telefono || "",
  servicio: item.servicio || "",
  fuente: item.fuente || "",
  empresa: item.empresa || "",
  estado: item.estado || "",
  pais: item.pais || "",
  codigo_postal: item.codigo_postal || "",
  direccion_ip: item.direccion_ip || "",
  identificador_externo: item.identificador_externo || "",
  url_origen: item.url_origen || "",
  user_agent: item.user_agent || "",
  nombre_formulario: item.nombre_formulario || "",
  nombre_campana: item.nombre_campana || "",
  nombre_conjunto_anuncios: item.nombre_conjunto_anuncios || "",
  nombre_anuncio: item.nombre_anuncio || "",
  nombre_pagina: item.nombre_pagina || "",
  estado_lead: item.estado_lead || "",
  fecha_creado: item.fecha_creado || "",
  fecha_creado_timestamp: item.fecha_creado_timestamp || "",
  created_at: item.created_at || "",
  updated_at: item.updated_at || "",
  fecha_conversion: item.fecha_conversion || "",
  enviado_meta: item.enviado_meta || "",
  score_lead: item.score_lead || "",
  mes_creacion: item.mes_creacion || "",
  ano_creacion: item.ano_creacion || "",
  utm_source: item.utm_source || "",
  utm_medium: item.utm_medium || "",
  utm_campaign: item.utm_campaign || "",
  utm_content: item.utm_content || "",
  utm_term: item.utm_term || "",
  fbclid: item.fbclid || "",
  fuente_completa: item.fuente_completa || "",
  campana_nombre: item.campana_nombre || "",
  anuncio_nombre: item.anuncio_nombre || "",
  error_meta: item.error_meta || "",
  client_id: item.client_id || "",
  messenger: item.messenger || "",
  instagram: item.instagram || "",
  whatsapp: item.whatsapp || "",
  telegram: item.telegram || "",
  messenger_normalizado: item.messenger_normalizado || "",
  instagram_normalizado: item.instagram_normalizado || "",
  telegram_normalizado: item.telegram_normalizado || "",
  identificado: item.identificado || "",
  nombre_normalizado: item.nombre_normalizado || "",
  es_cliente: item.es_cliente || "",
  fbp: item.fbp || "",
  conversationid: item.conversationid || "",
  accountid: item.accountid || "",
  content_type: item.content_type || "",
  private: item.private || "",
  content_attributes: item.content_attributes || "",
  contact_id: item.contact_id || "",
  sessionid: item.sessionid || "",
  agente: item.agente || "",
  message_type: item.message_type || "",
  sender: item.sender || "",
  chatwoot_contact_id: item.chatwoot_contact_id || "",
  instrucciones: instruccionesBrevesAgente,
  fecha_cita: item.fecha_cita || "",
  resumen: item.resumen || "",
  estado_cita: item.estado_cita || "",
  enlace_reunion: item.enlace_reunion || "",
  notas_internas: item.notas_internas || "",
  duracion_minutos: item.duracion_minutos || "",
  recordatorio_enviado: item.recordatorio_enviado || "",
  cancelado_por: item.cancelado_por || "",
  motivo_cancelacion: item.motivo_cancelacion || "",
  creado: item.creado || "",
  actualizado: item.actualizado || "",
  fecha_cita_timezone_cliente: item.fecha_cita_timezone_cliente || "",
  asistencia: item.asistencia || "",
  cita_pasada: item.cita_pasada || "",
  fecha_cita_timezone_legible: item.fecha_cita_timezone_legible || "",
  fecha_cita_legible: item.fecha_cita_legible || "",
  call_id: call.call_id || "",
  call_type: call.call_type || "",
  call_status: call.call_status || "",
  from_number: call.from_number || "",
  to_number: call.to_number || "",
  agent_id: call.agent_id || "",
  agent_name: call.agent_name || "",
  agent_version: call.agent_version || "",
  transcript: call.transcript || "",
  direction: call.direction || "",
  start_timestamp: call.start_timestamp || "",
  end_timestamp: call.end_timestamp || "",
  duration_ms: call.duration_ms || "",
  recording_url: call.recording_url || "",
  recording_multi_channel_url: call.recording_multi_channel_url || "",
  public_log_url: call.public_log_url || "",
  disconnection_reason: call.disconnection_reason || "",
  call_summary: call.call_analysis?.call_summary || "",
  resumenes_previos_concatenados: resumenesPrevios,
  event: item.body?.event || ""
};

// Dynamic variables (todas en string)
const dynamic_variables = {
  nombre: String(
  (() => {
    const partes = (item.nombre || "sin_dato")
      .trim()
      .split(/\s+/)
      .filter(Boolean); // limpia espacios vacíos

    if (partes.length === 0) return "sin_dato";

    // Primer nombre siempre
    const primerNombre = partes[0];

    // Primer apellido si existe (segunda palabra o penúltima si hay más de dos)
    let primerApellido = "";
    if (partes.length >= 2) {
      primerApellido = partes.length === 2 ? partes[1] : partes[partes.length - 2];
    }

    // Formatear con mayúsculas iniciales
    const format = (str) =>
      str.charAt(0).toUpperCase() + str.slice(1).toLowerCase();

    return primerApellido
      ? `${format(primerNombre)} ${format(primerApellido)}`
      : format(primerNombre);
  })()
),
  nombre_completo: String(item.nombre || "sin_dato"),
  email: String(item.email || "sin_dato"),
  telefono: String(item.telefono || call.from_number || "sin_dato"),
  servicio: String(item.servicio || "sin_dato"),
  empresa: String(item.empresa || "sin_dato"),
  estado: String(item.estado || "sin_dato"),
  pais: String(item.pais || "sin_dato"),
  estado_lead: String(item.estado_lead || "sin_dato"),
  client_id: String(item.client_id || "sin_dato"),
  whatsapp: String(item.whatsapp || "sin_dato"),
  es_cliente: String(item.es_cliente || "sin_dato"),
  fecha_cita: String(item.fecha_cita || "sin_dato"),
  enlace_reunion: String(item.enlace_reunion || "sin_dato"),
  motivo_cancelacion: String(item.motivo_cancelacion || "sin_dato"),
  fecha_cita_timezone_cliente: String(item.fecha_cita_timezone_cliente || "sin_dato"),
  asistencia: String(item.asistencia || "sin_dato"),
  cita_pasada: String(item.cita_pasada || "sin_dato"),
  fecha_cita_timezone_legible: String(item.fecha_cita_timezone_legible || "sin_dato"),
  fecha_cita_legible: String(item.fecha_cita_legible || "sin_dato"),
  call_id: String(call.call_id || "sin_dato"),
  call_type: String(call.call_type || "sin_dato"),
  call_status: String(call.call_status || "sin_dato"),
  from_number: String(call.from_number || "sin_dato"),
  to_number: String(call.to_number || "sin_dato"),
  agent_id: String(call.agent_id || "sin_dato"),
  agent_name: String(call.agent_name || "sin_dato"),
  agent_version: String(call.agent_version || "sin_dato"),
  direction: String(call.direction || "sin_dato"),
  resumenes_previos: String(resumenesPrevios || "sin_dato"),
  estado_cita: String(item.estado_cita || "sin_dato"),
  event: String(item.body?.event || "sin_dato")
};

// Construcción final en el formato que espera Retell
const response = {
  call_inbound: {
    override_agent_id: call.agent_id || undefined,
    override_agent_version: call.agent_version || undefined,
    dynamic_variables,
    metadata
  }
};

// Retornar como JSON STRING
return [
  {
    json: {
      jsonString: JSON.stringify(response, null, 2),
      data: response
    }
  }
];

