={{
(() => {
  let fechaRaw =  $('Set call fields').item.json.hora_inicio_mexico ;
  if (!fechaRaw) return 'Sin fecha';

  // Normaliza formato básico
  fechaRaw = fechaRaw.replace(' ', 'T').replace(/\//g, '-');

  // Solo agrega Z si no hay zona horaria ni Z
  if (!/[+-]\d{2}:\d{2}$/.test(fechaRaw) && !fechaRaw.endsWith('Z')) {
    fechaRaw += 'Z';
  }

  const fecha = new Date(fechaRaw);
  if (isNaN(fecha.getTime())) return 'Fecha inválida';

  // Devuelve fecha y hora con formato mexicano
  return fecha.toLocaleString('es-MX', {
    timeZone: 'America/Mexico_City',
    weekday: 'long',
    day: 'numeric',
    month: 'long',
    year: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
    hour12: true
  });
})()
}}

